class SearchViewModel(
    private val repository: SearchRepository
) : ViewModel() {
    private val rawQuery = MutableStateFlow("")
    private val selectedCity = MutableStateFlow<String?>(null)

    fun onQueryChanged(value: String) {
        rawQuery.value = value
    }

    fun onCityChanged(value: String?) {
        selectedCity.value = value
    }
}

val uiState: StateFlow<SearchUiState> =
    combine(
        rawQuery.map(::normalizeQuery)
            .distinctUntilChanged()
            .debounce(350),
        selectedCity
    ) { query, city -> SearchCriteria(query, city) }
        .flatMapLatest { criteria ->
            if (criteria.query.length < 2) {
                flowOf(SearchUiState.Idle)
            } else {
                repository.search(criteria)
                    .map<SearchResult, SearchUiState> { SearchUiState.Content(it.items) }
                    .onStart { emit(SearchUiState.Loading(previous = null)) }
                    .catch { error -> emit(error.toSearchUiState()) }
            }
        }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            initialValue = SearchUiState.Idle
        )

private val generation = AtomicLong(0)

suspend fun searchLatest(criteria: SearchCriteria): SearchResult {
    val token = generation.incrementAndGet()
    val result = legacySearch(criteria)
    if (token != generation.get()) throw CancellationException("Stale generation")
    return result
}

repository.search(criteria)
    .retryWhen { cause, attempt ->
        val retryable = cause is IOException && attempt < 2
        if (retryable) delay(300L * (attempt + 1))
        retryable
    }
    .catch { cause ->
        if (cause is CancellationException) throw cause
        emit(SearchResult.Failure(cause.toSearchError()))
    }

private val inFlight = Mutex()
private val requests = mutableMapOf<SearchCriteria, Deferred<SearchResult>>()

suspend fun search(criteria: SearchCriteria): SearchResult = coroutineScope {
    val deferred = inFlight.withLock {
        requests[criteria] ?: async { api.search(criteria) }
            .also { requests[criteria] = it }
    }
    try {
        deferred.await()
    } finally {
        inFlight.withLock {
            if (requests[criteria] === deferred) requests.remove(criteria)
        }
    }
}

val pagingData = criteria
    .filter { it.query.length >= 2 }
    .flatMapLatest { criteria ->
        Pager(
            config = PagingConfig(pageSize = 20),
            pagingSourceFactory = { repository.searchPagingSource(criteria) }
        ).flow
    }
    .cachedIn(viewModelScope)

@Composable
fun SearchRoute(viewModel: SearchViewModel) {
    val state by viewModel.uiState.collectAsStateWithLifecycle()
    SearchScreen(
        state = state,
        onQueryChanged = viewModel::onQueryChanged
    )
}

repository.search(criteria)
    .map { result -> heavyRank(result, criteria) }
    .flowOn(Dispatchers.Default)
